from niltest import Mode, configure, expect, run_tests, scenario

configure(mode=Mode.TEST)  # Set before importing decorated modules.

@scenario("Shipping fee")
def shipping_fee(subtotal: int, premium: bool = False) -> int:
    if expect:
        expect.case(
            "premium ships free",
            given={"subtotal": 1_000, "premium": True},
            returns=0,
        )
    return 0 if premium or subtotal >= 5_000 else 500

assert run_tests(shipping_fee).success
